template.script:
document.addEventListener('DOMContentLoaded', function() {
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -50px 0px'
};

const observer = new IntersectionObserver(function(entries) {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.closest('.petroraq-projects-page').classList.add('animate-loaded');
}
});
}, observerOptions);

// Observe sections
document.querySelectorAll('.pr-hero, .pr-confidence, .pr-featured, .pr-categories, .pr-cta').forEach(section
=> {
observer.observe(section);
});

// Smooth hover effects for cards
document.querySelectorAll('.pr-card, .pr-stat, .pr-cat-card').forEach(card => {
card.addEventListener('mouseenter', function() {
this.style.transform = 'translateY(-12px) scale(1.02)';
});
card.addEventListener('mouseleave', function() {
this.style.transform = 'translateY(0) scale(1)';
});
});

// Parallax effect for hero
window.addEventListener('scroll', function() {
const scrolled = window.pageYOffset;
const hero = document.querySelector('.pr-hero-right');
if (hero) {
hero.style.transform = `translateY(${scrolled * 0.5}px) scale(1.02)`;
}
});
});
